import React, { useState, useEffect } from 'react';
import { studentAPI } from '../services/api';
import toast from 'react-hot-toast';

// Format date safely - strip time part
function fmtDate(d) {
  if (!d) return '—';
  return String(d).split('T')[0];
}

const FEE_BADGE = {
  paid:    { bg:'#D1FAE5', c:'#065F46', label:'✓ Paid'  },
  pending: { bg:'#FEE2E2', c:'#991B1B', label:'Pending'  },
  partial: { bg:'#FEF3C7', c:'#92400E', label:'Partial'  },
};

const CLASSES = ['Class 1','Class 2','Class 3','Class 4','Class 5','Class 6','Class 7','Class 8','Class 9','Class 10','Class 11','Class 12'];

// ── Mock fallback when backend is not connected ───────────
const MOCK_STUDENTS = [
  { id:1,  admission_no:'ADM2501', first_name:'Aarav',  last_name:'Sharma',  class_name:'Class 10',section_name:'A', parent_name:'Rajesh Sharma',  parent_phone:'9876543210', category:'general', fee_status:'paid',    status:'active', date_of_birth:'2009-03-14', gender:'male' },
  { id:2,  admission_no:'ADM2502', first_name:'Priya',  last_name:'Singh',   class_name:'Class 8', section_name:'B', parent_name:'Manoj Singh',    parent_phone:'9765432100', category:'obc',     fee_status:'pending', status:'active', date_of_birth:'2011-07-22', gender:'female' },
  { id:3,  admission_no:'ADM2503', first_name:'Rohit',  last_name:'Gupta',   class_name:'Class 12',section_name:'A', parent_name:'Suresh Gupta',   parent_phone:'9988776655', category:'general', fee_status:'paid',    status:'active', date_of_birth:'2007-11-05', gender:'male' },
  { id:4,  admission_no:'ADM2504', first_name:'Ananya', last_name:'Patel',   class_name:'Class 6', section_name:'C', parent_name:'Deepak Patel',   parent_phone:'9765432108', category:'sc',      fee_status:'partial', status:'active', date_of_birth:'2013-05-19', gender:'female' },
  { id:5,  admission_no:'ADM2505', first_name:'Dev',    last_name:'Kumar',   class_name:'Class 11',section_name:'B', parent_name:'Anil Kumar',     parent_phone:'9543218760', category:'general', fee_status:'pending', status:'active', date_of_birth:'2008-09-30', gender:'male' },
  { id:6,  admission_no:'ADM2506', first_name:'Sakshi', last_name:'Verma',   class_name:'Class 9', section_name:'A', parent_name:'Vivek Verma',    parent_phone:'9812345670', category:'general', fee_status:'paid',    status:'active', date_of_birth:'2010-12-01', gender:'female' },
  { id:7,  admission_no:'ADM2507', first_name:'Arjun',  last_name:'Mishra',  class_name:'Class 7', section_name:'A', parent_name:'Sunil Mishra',   parent_phone:'9765001234', category:'obc',     fee_status:'paid',    status:'active', date_of_birth:'2012-02-17', gender:'male' },
  { id:8,  admission_no:'ADM2508', first_name:'Neha',   last_name:'Tiwari',  class_name:'Class 10',section_name:'B', parent_name:'Ramesh Tiwari',  parent_phone:'9634567890', category:'general', fee_status:'partial', status:'active', date_of_birth:'2009-08-24', gender:'female' },
  { id:9,  admission_no:'ADM2509', first_name:'Vikram', last_name:'Joshi',   class_name:'Class 8', section_name:'A', parent_name:'Kailash Joshi',  parent_phone:'9876001234', category:'ews',     fee_status:'pending', status:'active', date_of_birth:'2011-04-11', gender:'male' },
  { id:10, admission_no:'ADM2510', first_name:'Kavya',  last_name:'Rao',     class_name:'Class 6', section_name:'A', parent_name:'Naresh Rao',     parent_phone:'9754321098', category:'general', fee_status:'paid',    status:'active', date_of_birth:'2013-01-28', gender:'female' },
];

const EMPTY = {
  firstName:'', lastName:'', dob:'', gender:'male', blood:'', category:'general', photoUrl:null,
  aadhaar:'', religion:'', class_:'', section:'A',
  admDate: new Date().toISOString().split('T')[0],
  prevSchool:'', prevMarks:'',
  fatherName:'', motherName:'', phone:'', altPhone:'', email:'',
  city:'', state:'Uttar Pradesh', pincode:'', address:'',
};

const inp = (extra={}) => ({ width:'100%', padding:'10px 12px', border:'1.5px solid '+(extra.error?'#DC2626':'#E5E7EB'), borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' });

const Field = ({ label, required, error, children }) => (
  <div style={{display:'flex',flexDirection:'column',gap:5}}>
    <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em'}}>
      {label}{required&&<span style={{color:'#DC2626',marginLeft:3}}>*</span>}
    </label>
    {children}
    {error&&<span style={{color:'#DC2626',fontSize:11,marginTop:2}}>{error}</span>}
  </div>
);

const Divider = ({title}) => (
  <div style={{fontSize:11,fontWeight:800,color:'#1E1B4B',textTransform:'uppercase',letterSpacing:'.08em',margin:'20px 0 12px',paddingBottom:8,borderBottom:'2px solid #EDE9F8'}}>{title}</div>
);

export default function Students() {
  const [students,   setStudents]   = useState([]);
  const [loading,    setLoading]    = useState(true);
  const [isMock,     setIsMock]     = useState(false);
  const [total,      setTotal]      = useState(0);
  const [search,     setSearch]     = useState('');
  const [filterCls,  setFilterCls]  = useState('');
  const [filterFee,  setFilterFee]  = useState('');
  const [page,       setPage]       = useState(1);
  const [showAdd,    setShowAdd]    = useState(false);
  const [viewSt,     setViewSt]     = useState(null);
  const [step,       setStep]       = useState(1);
  const [form,       setForm]       = useState(EMPTY);
  const [errors,     setErrors]     = useState({});
  const [saving,     setSaving]     = useState(false);

  const f = (k,v) => setForm(p=>({...p,[k]:v}));

  // ── Load students ────────────────────────────────────────
  const loadStudents = async () => {
    setLoading(true);
    try {
      const res = await studentAPI.getAll({ page, limit:15, search, feeStatus: filterFee });
      setStudents(res.data.data || []);
      setTotal(res.data.pagination?.total || 0);
      setIsMock(false);
    } catch (err) {
      // Backend not available — use mock data
      console.warn('Backend not available, using mock data:', err.message);
      let filtered = [...MOCK_STUDENTS];
      if (search) filtered = filtered.filter(s => `${s.first_name} ${s.last_name}`.toLowerCase().includes(search.toLowerCase()) || s.admission_no.includes(search));
      if (filterFee) filtered = filtered.filter(s => s.fee_status === filterFee);
      if (filterCls) filtered = filtered.filter(s => s.class_name === filterCls);
      setStudents(filtered);
      setTotal(filtered.length);
      setIsMock(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadStudents(); }, [page, search, filterFee, filterCls]);

  // ── Validate ────────────────────────────────────────────
  const validate = () => {
    const e = {};
    if (step===1) {
      if (!form.firstName.trim()) e.firstName = 'Required';
      if (!form.dob)              e.dob       = 'Required';
    }
    if (step===2) {
      if (!form.fatherName.trim()) e.fatherName = 'Required';
      if (!form.phone.trim())      e.phone      = 'Required';
      if (form.phone && !/^\d{10}$/.test(form.phone)) e.phone = 'Must be 10 digits';
    }
    if (step===3) {
      if (!form.class_.trim()) e.class_ = 'Please select a class';
    }
    setErrors(e);
    return !Object.keys(e).length;
  };

  const openAdd  = () => { setForm(EMPTY); setErrors({}); setStep(1); setShowAdd(true); setViewSt(null); };
  const closeAdd = () => { setShowAdd(false); setErrors({}); setStep(1); };

  // ── Save student ────────────────────────────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validate()) return;
    if (step < 3) { setStep(step+1); return; }

    setSaving(true);
    const payload = {
      firstName:      form.firstName,
      lastName:       form.lastName,
      dateOfBirth:    form.dob,
      gender:         form.gender,
      bloodGroup:     form.blood || undefined,
      category:       form.category,
      aadhaarNo:      form.aadhaar || undefined,
      religion:       form.religion || undefined,
      className:      form.class_,      // send name — backend resolves to UUID
      sectionName:    form.section,     // send name — backend resolves to UUID
      admissionDate:  form.admDate,
      previousSchool: form.prevSchool || undefined,
      addressLine1:   form.address || undefined,
      city:           form.city || undefined,
      state:          form.state || undefined,
      pincode:        form.pincode || undefined,
      photoUrl:       form.photoUrl || undefined,
      parents: [{
        relation:          'father',
        fullName:          form.fatherName,
        phone:             form.phone,
        alternatePhone:    form.altPhone || undefined,
        email:             form.email || undefined,
        isPrimaryContact:  true,
      }],
    };
    if (form.motherName) {
      payload.parents.push({ relation:'mother', fullName:form.motherName, phone:'', isPrimaryContact:false });
    }

    try {
      await studentAPI.create(payload);
      toast.success(`✅ ${form.firstName} ${form.lastName} admitted! Saved to database.`);
      closeAdd();
      loadStudents();
    } catch (err) {
      // If backend fails, add to local list only
      const mockNew = {
        id:           Date.now(),
        admission_no: `ADM${Date.now().toString().slice(-4)}`,
        first_name:   form.firstName,
        last_name:    form.lastName,
        class_name:   form.class_,
        section_name: form.section,
        parent_name:  form.fatherName,
        parent_phone: form.phone,
        category:     form.category,
        fee_status:   'pending',
        status:       'active',
        date_of_birth:form.dob,
        gender:       form.gender,
      };
      setStudents(prev => [mockNew, ...prev]);
      setTotal(t => t+1);
      setIsMock(true);
      toast.success(`✅ ${form.firstName} ${form.lastName} added! (Note: connect backend to save to DB)`);
      closeAdd();
    } finally {
      setSaving(false);
    }
  };

  const STEPS = ['Student Info', 'Parent Info', 'Academic Details'];

  return (
    <div style={{position:'relative'}}>
      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:18}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Students</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {total} students enrolled
            {isMock && <span style={{marginLeft:8,padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode — connect backend to save to DB</span>}
            {!isMock && <span style={{marginLeft:8,padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live database</span>}
          </p>
        </div>
        <div style={{display:'flex',gap:10}}>
          <button style={{padding:'9px 14px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:12,fontWeight:600,cursor:'pointer'}}>📥 Export Excel</button>
          <button onClick={openAdd} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Admission</button>
        </div>
      </div>

      {/* Filters */}
      <div style={{display:'flex',gap:10,marginBottom:16,flexWrap:'wrap'}}>
        <input placeholder="🔍 Search by name, admission no…" value={search} onChange={e=>{setSearch(e.target.value);setPage(1);}}
          style={{...inp(),maxWidth:300,flex:1}}/>
        <select value={filterCls} onChange={e=>{setFilterCls(e.target.value);setPage(1);}} style={{...inp(),width:'auto'}}>
          <option value=''>All Classes</option>{CLASSES.map(c=><option key={c}>{c}</option>)}
        </select>
        <select value={filterFee} onChange={e=>{setFilterFee(e.target.value);setPage(1);}} style={{...inp(),width:'auto'}}>
          <option value=''>Fee: All</option>
          <option value='paid'>Paid</option>
          <option value='pending'>Pending</option>
          <option value='partial'>Partial</option>
        </select>
        {(search||filterCls||filterFee)&&(
          <button onClick={()=>{setSearch('');setFilterCls('');setFilterFee('');setPage(1);}} style={{padding:'9px 14px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:12,color:'#6B7280',cursor:'pointer'}}>Clear ✕</button>
        )}
      </div>

      {/* Table */}
      <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12}}>
          <thead><tr style={{background:'#F9FAFB'}}>
            {['Photo','Adm No.','Student','Class / Sec','Parent / Phone','Category','Fee','Status','Actions'].map(h=>(
              <th key={h} style={{padding:'10px 14px',textAlign:'left',color:'#6B7280',fontSize:10,fontWeight:700,textTransform:'uppercase',borderBottom:'1px solid #E5E7EB',whiteSpace:'nowrap'}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>
            {loading&&<tr><td colSpan={8} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:24,marginBottom:8}}>⏳</div>Loading students…
            </td></tr>}
            {!loading&&students.length===0&&<tr><td colSpan={8} style={{padding:48,textAlign:'center',color:'#9CA3AF'}}>
              <div style={{fontSize:36,marginBottom:10}}>👨‍🎓</div>
              <div style={{fontWeight:600,color:'#6B7280'}}>No students found</div>
              <div style={{fontSize:12,marginTop:4}}>Add students or run the database seed file</div>
            </td></tr>}
            {!loading&&students.map((s,idx)=>{
              const name = `${s.first_name} ${s.last_name}`.trim();
              const fb   = FEE_BADGE[s.fee_status] || FEE_BADGE.pending;
              return (
                <tr key={s.id||idx} style={{borderBottom:'0.5px solid #F3F4F6',transition:'background .1s'}}
                  onMouseEnter={e=>e.currentTarget.style.background='#F5F3FF'}
                  onMouseLeave={e=>e.currentTarget.style.background=''}>
                  <td style={{padding:'8px 12px'}}>
                    {s.photo_url
                      ? <img src={s.photo_url} alt="" style={{width:36,height:36,borderRadius:8,objectFit:'cover',border:'1.5px solid #E5E7EB'}}/>
                      : <div style={{width:36,height:36,borderRadius:8,background:'#F3F4F6',display:'flex',alignItems:'center',justifyContent:'center',fontSize:16,color:'#9CA3AF'}}>👤</div>}
                  </td>
                  <td style={{padding:'11px 14px',fontFamily:'monospace',fontSize:11,color:'#9CA3AF'}}>{s.admission_no}</td>
                  <td style={{padding:'11px 14px'}}>
                    <div style={{display:'flex',alignItems:'center',gap:9}}>
                      <div style={{width:32,height:32,borderRadius:8,background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{name[0]}</div>
                      <div>
                        <div style={{fontWeight:700,color:'#111827'}}>{name}</div>
                        <div style={{fontSize:10,color:'#9CA3AF'}}>{s.gender} · {s.date_of_birth}</div>
                      </div>
                    </div>
                  </td>
                  <td style={{padding:'11px 14px',fontWeight:500,color:'#374151'}}>{s.class_name} — {s.section_name}</td>
                  <td style={{padding:'11px 14px'}}>
                    <div style={{fontWeight:500}}>{s.parent_name}</div>
                    <div style={{fontSize:10,color:'#9CA3AF'}}>{s.parent_phone}</div>
                  </td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:'#F3F4F6',color:'#374151',textTransform:'uppercase'}}>{s.category}</span></td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:fb.bg,color:fb.c}}>{fb.label}</span></td>
                  <td style={{padding:'11px 14px'}}><span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:600,background:s.status==='active'?'#D1FAE5':'#F3F4F6',color:s.status==='active'?'#065F46':'#374151'}}>{s.status}</span></td>
                  <td style={{padding:'11px 14px'}}>
                    <div style={{display:'flex',gap:6}}>
                      <button onClick={()=>setViewSt(s)} style={{padding:'5px 12px',border:'1px solid #1E1B4B',borderRadius:7,background:'#EDE9F8',color:'#1E1B4B',fontSize:11,fontWeight:600,cursor:'pointer'}}>View</button>
                      <button onClick={()=>toast.success(`ID Card for ${name}`)} style={{padding:'5px 10px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>ID</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>

        {/* Pagination */}
        <div style={{padding:'10px 14px',borderTop:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',fontSize:11,color:'#6B7280'}}>
          <span>Showing <strong>{students.length}</strong> of <strong>{total}</strong> students</span>
          <div style={{display:'flex',gap:6}}>
            {page>1&&<button onClick={()=>setPage(p=>p-1)} style={{padding:'5px 12px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>← Prev</button>}
            <span style={{padding:'5px 12px',background:'#1E1B4B',color:'#fff',borderRadius:7,fontWeight:700}}>Page {page}</span>
            {students.length===15&&<button onClick={()=>setPage(p=>p+1)} style={{padding:'5px 12px',border:'1px solid #E5E7EB',borderRadius:7,background:'#fff',fontSize:11,cursor:'pointer'}}>Next →</button>}
          </div>
        </div>
      </div>

      {/* VIEW STUDENT */}
      {viewSt&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.5)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:500,maxHeight:'90vh',overflow:'auto'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff'}}>
              <div style={{fontWeight:700,fontSize:15}}>👨‍🎓 Student Profile</div>
              <button onClick={()=>setViewSt(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <div style={{padding:22}}>
              <div style={{display:'flex',alignItems:'center',gap:14,padding:16,background:'#EDE9F8',borderRadius:12,marginBottom:20}}>
                {viewSt.photo_url
                  ? <img src={viewSt.photo_url} alt="" style={{width:64,height:64,borderRadius:14,objectFit:'cover',flexShrink:0,border:'3px solid #fff',boxShadow:'0 2px 12px rgba(0,0,0,.2)'}}/>
                  : <div style={{width:64,height:64,borderRadius:14,background:'#1E1B4B',display:'flex',alignItems:'center',justifyContent:'center',fontSize:26,fontWeight:700,color:'#fff',flexShrink:0}}>{viewSt.first_name?.[0]}</div>}
                <div>
                  <div style={{fontSize:17,fontWeight:800,color:'#111827'}}>{viewSt.first_name} {viewSt.last_name}</div>
                  <div style={{fontSize:12,color:'#6B7280',marginTop:2}}>Admission No: <strong>{viewSt.admission_no}</strong></div>
                  <div style={{display:'flex',gap:7,marginTop:6,flexWrap:'wrap'}}>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#1E1B4B',color:'#fff'}}>{viewSt.class_name} {viewSt.section_name}</span>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:(FEE_BADGE[viewSt.fee_status]||FEE_BADGE.pending).bg,color:(FEE_BADGE[viewSt.fee_status]||FEE_BADGE.pending).c}}>{(FEE_BADGE[viewSt.fee_status]||FEE_BADGE.pending).label}</span>
                    <span style={{padding:'2px 8px',borderRadius:20,fontSize:10,background:'#D1FAE5',color:'#065F46'}}>{viewSt.status}</span>
                  </div>
                </div>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
                {[['Date of Birth',fmtDate(viewSt.date_of_birth)||'—'],['Gender',viewSt.gender||'—'],['Category',viewSt.category||'—'],['Roll No',viewSt.roll_no||'—'],['Parent',viewSt.parent_name||'—'],['Phone',viewSt.parent_phone||'—'],['Admission Date',fmtDate(viewSt.admission_date)||'—'],['Status',viewSt.status]].map(([k,v])=>(
                  <div key={k} style={{padding:'10px 12px',background:'#F9FAFB',borderRadius:9}}>
                    <div style={{fontSize:10,color:'#9CA3AF',fontWeight:700,textTransform:'uppercase',marginBottom:4}}>{k}</div>
                    <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{v}</div>
                  </div>
                ))}
              </div>
              <div style={{display:'flex',gap:10,marginTop:18}}>
                <button onClick={()=>toast.success('Collect fee!')} style={{flex:1,padding:'10px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:600,cursor:'pointer'}}>💰 Collect Fee</button>
                <button onClick={()=>toast.success('ID card!')} style={{flex:1,padding:'10px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>📄 ID Card</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ADD STUDENT DRAWER */}
      {showAdd&&(
        <>
          <div onClick={closeAdd} style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400}}/>
          <div style={{position:'fixed',top:0,right:0,bottom:0,width:480,maxWidth:'100vw',background:'#fff',zIndex:500,display:'flex',flexDirection:'column',boxShadow:'-8px 0 40px rgba(0,0,0,.15)'}}>
            <div style={{padding:'18px 22px',borderBottom:'1px solid #E5E7EB',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0}}>
              <div>
                <div style={{fontSize:16,fontWeight:800,color:'#111827'}}>🎓 New Student Admission</div>
                <div style={{fontSize:12,color:'#6B7280',marginTop:2}}>Step {step} of 3 — {STEPS[step-1]}</div>
              </div>
              <button onClick={closeAdd} style={{background:'#F3F4F6',border:'none',borderRadius:9,width:34,height:34,cursor:'pointer',fontSize:18,color:'#374151',display:'flex',alignItems:'center',justifyContent:'center'}}>✕</button>
            </div>

            {/* Steps */}
            <div style={{padding:'14px 22px',borderBottom:'1px solid #F3F4F6',display:'flex',flexShrink:0}}>
              {STEPS.map((label,i)=>{
                const n=i+1,done=step>n,active=step===n;
                return (
                  <div key={n} style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:5,position:'relative'}}>
                    {i<2&&<div style={{position:'absolute',top:12,left:'55%',right:'-45%',height:2,background:done?'#1E1B4B':'#E5E7EB',zIndex:0}}/>}
                    <div style={{width:26,height:26,borderRadius:'50%',background:done||active?'#1E1B4B':'#F3F4F6',color:done||active?'#fff':'#9CA3AF',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:800,zIndex:1,border:'2px solid '+(done||active?'#1E1B4B':'#E5E7EB'),position:'relative'}}>
                      {done?'✓':n}
                    </div>
                    <div style={{fontSize:10,fontWeight:700,color:active?'#1E1B4B':done?'#6B7280':'#9CA3AF',textAlign:'center'}}>{label}</div>
                  </div>
                );
              })}
            </div>

            <form onSubmit={handleSubmit} style={{flex:1,overflowY:'auto',padding:'18px 22px'}}>
              {step===1&&(
                <>
                  {/* Photo upload row */}
                  <div style={{display:'flex',gap:20,padding:14,background:'#F9FAFB',borderRadius:12,marginBottom:16,alignItems:'flex-start'}}>
                    <div style={{flexShrink:0,textAlign:'center'}}>
                      <div style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:6}}>Photo</div>
                      <div
                        onClick={()=>{const inp=document.getElementById('student-photo-inp');if(inp)inp.click();}}
                        style={{width:90,height:96,borderRadius:10,border:form.photoUrl?'none':'2px dashed #C4B5FD',background:form.photoUrl?'transparent':'#EDE9F8',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',cursor:'pointer',overflow:'hidden',position:'relative'}}>
                        {form.photoUrl
                          ? <img src={form.photoUrl} alt="" style={{width:'100%',height:'100%',objectFit:'cover'}}/>
                          : <><span style={{fontSize:24}}>📷</span><span style={{fontSize:9,color:'#7C3AED',fontWeight:600,marginTop:4,textAlign:'center',padding:'0 6px'}}>Upload Photo</span></>}
                      </div>
                      <input id="student-photo-inp" type="file" accept="image/*" onChange={e=>{
                        const file=e.target.files[0];
                        if(!file)return;
                        if(file.size>3*1024*1024){alert('Photo must be under 3MB');return;}
                        const r=new FileReader();
                        r.onload=ev=>f('photoUrl',ev.target.result);
                        r.readAsDataURL(file);
                      }} style={{display:'none'}}/>
                      {form.photoUrl&&<button type="button" onClick={()=>f('photoUrl',null)} style={{fontSize:10,color:'#DC2626',background:'none',border:'none',cursor:'pointer',marginTop:4}}>Remove</button>}
                      {!form.photoUrl&&<div style={{fontSize:9,color:'#9CA3AF',marginTop:4}}>JPG/PNG ≤3MB</div>}
                    </div>
                    <div style={{flex:1}}>
                      <Divider title="Personal Details"/>
                      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                        <Field label="First Name" required error={errors.firstName}>
                          <input value={form.firstName} onChange={e=>f('firstName',e.target.value)} placeholder="First name" style={inp({error:errors.firstName})} autoFocus/>
                        </Field>
                        <Field label="Last Name">
                          <input value={form.lastName} onChange={e=>f('lastName',e.target.value)} placeholder="Last name" style={inp()}/>
                        </Field>
                      </div>
                    </div>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Date of Birth" required error={errors.dob}>
                      <input type="date" value={form.dob} onChange={e=>f('dob',e.target.value)} style={inp({error:errors.dob})} max={today}/>
                    </Field>
                    <Field label="Gender">
                      <select value={form.gender} onChange={e=>f('gender',e.target.value)} style={inp()}>
                        <option value="male">Male</option><option value="female">Female</option><option value="other">Other</option>
                      </select>
                    </Field>
                    <Field label="Blood Group">
                      <select value={form.blood} onChange={e=>f('blood',e.target.value)} style={inp()}>
                        <option value="">Select</option>{['A+','A-','B+','B-','O+','O-','AB+','AB-'].map(b=><option key={b}>{b}</option>)}
                      </select>
                    </Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Category">
                      <select value={form.category} onChange={e=>f('category',e.target.value)} style={inp()}>
                        <option value="general">General</option><option value="obc">OBC</option><option value="sc">SC</option><option value="st">ST</option><option value="ews">EWS</option>
                      </select>
                    </Field>
                    <Field label="Religion">
                      <input value={form.religion} onChange={e=>f('religion',e.target.value)} placeholder="e.g. Hindu" style={inp()}/>
                    </Field>
                  </div>
                  <Field label="Aadhaar Number">
                    <input value={form.aadhaar} onChange={e=>f('aadhaar',e.target.value)} placeholder="12-digit (optional)" style={inp()} maxLength={12}/>
                  </Field>
                </>
              )}
              {step===2&&(
                <>
                  <Divider title="Parent / Guardian Details"/>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Father's Name" required error={errors.fatherName}>
                      <input value={form.fatherName} onChange={e=>f('fatherName',e.target.value)} placeholder="Father's full name" style={inp({error:errors.fatherName})} autoFocus/>
                    </Field>
                    <Field label="Mother's Name">
                      <input value={form.motherName} onChange={e=>f('motherName',e.target.value)} placeholder="Mother's full name" style={inp()}/>
                    </Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Primary Mobile" required error={errors.phone}>
                      <input value={form.phone} onChange={e=>f('phone',e.target.value)} placeholder="10-digit mobile" style={inp({error:errors.phone})} maxLength={10}/>
                    </Field>
                    <Field label="Alternate Mobile">
                      <input value={form.altPhone} onChange={e=>f('altPhone',e.target.value)} placeholder="Optional" style={inp()} maxLength={10}/>
                    </Field>
                  </div>
                  <Field label="Email Address">
                    <input type="email" value={form.email} onChange={e=>f('email',e.target.value)} placeholder="parent@email.com" style={{...inp(),marginBottom:12}}/>
                  </Field>
                  <Divider title="Address"/>
                  <Field label="Full Address">
                    <textarea value={form.address} onChange={e=>f('address',e.target.value)} placeholder="House no., Street, Locality…" rows={2} style={{...inp(),resize:'vertical',marginBottom:12}}/>
                  </Field>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12}}>
                    <Field label="City"><input value={form.city} onChange={e=>f('city',e.target.value)} placeholder="Lucknow" style={inp()}/></Field>
                    <Field label="State"><input value={form.state} onChange={e=>f('state',e.target.value)} style={inp()}/></Field>
                    <Field label="Pincode"><input value={form.pincode} onChange={e=>f('pincode',e.target.value)} placeholder="226001" style={inp()} maxLength={6}/></Field>
                  </div>
                </>
              )}
              {step===3&&(
                <>
                  <Divider title="Academic Placement"/>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:12}}>
                    <Field label="Class" required error={errors.class_}>
                      <select value={form.class_} onChange={e=>f('class_',e.target.value)} style={inp({error:errors.class_})}>
                        <option value="">Select Class</option>{CLASSES.map(c=><option key={c}>{c}</option>)}
                      </select>
                    </Field>
                    <Field label="Section">
                      <select value={form.section} onChange={e=>f('section',e.target.value)} style={inp()}>
                        {['A','B','C','D'].map(s=><option key={s}>{s}</option>)}
                      </select>
                    </Field>
                    <Field label="Admission Date">
                      <input type="date" value={form.admDate} onChange={e=>f('admDate',e.target.value)} style={inp()}/>
                    </Field>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:18}}>
                    <Field label="Previous School"><input value={form.prevSchool} onChange={e=>f('prevSchool',e.target.value)} placeholder="Previous school" style={inp()}/></Field>
                    <Field label="Prev Class / Marks%"><input value={form.prevMarks} onChange={e=>f('prevMarks',e.target.value)} placeholder="e.g. Class 5 · 82%" style={inp()}/></Field>
                  </div>
                  <div style={{padding:14,background:'#EDE9F8',borderRadius:12,marginBottom:14,fontSize:12}}>
                    <div style={{fontWeight:800,color:'#1E1B4B',marginBottom:8}}>📋 Summary</div>
                    <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6,color:'#374151'}}>
                      {[['Name',`${form.firstName} ${form.lastName}`.trim()||'—'],['DOB',form.dob||'—'],['Class',form.class_?`${form.class_} - ${form.section}`:'—'],['Father',form.fatherName||'—'],['Phone',form.phone||'—'],['Category',form.category]].map(([k,v])=>(
                        <div key={k}><span style={{color:'#6B7280'}}>{k}: </span><strong>{v}</strong></div>
                      ))}
                    </div>
                  </div>
                  {isMock&&<div style={{padding:12,background:'#FEF3C7',borderRadius:10,fontSize:12,color:'#92400E',marginBottom:12}}>
                    ⚠️ Backend not connected — student will be added to local list only. Run backend + seed to save to PostgreSQL.
                  </div>}
                  {!isMock&&<div style={{padding:12,background:'#D1FAE5',borderRadius:10,fontSize:12,color:'#065F46',marginBottom:12}}>
                    ✅ Connected to database — student will be saved to PostgreSQL.
                  </div>}
                </>
              )}
              <div style={{display:'flex',justifyContent:'space-between',marginTop:20,paddingTop:16,borderTop:'1px solid #F3F4F6',gap:10}}>
                <button type="button" onClick={closeAdd} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <div style={{display:'flex',gap:10}}>
                  {step>1&&<button type="button" onClick={()=>setStep(step-1)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,fontWeight:600,cursor:'pointer'}}>← Back</button>}
                  <button type="submit" disabled={saving} style={{padding:'10px 24px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:800,cursor:saving?'wait':'pointer'}}>
                    {saving?'⏳ Saving…':step<3?'Next Step →':'🎓 Admit Student'}
                  </button>
                </div>
              </div>
            </form>
          </div>
        </>
      )}
    </div>
  );
}

const today = new Date().toISOString().split('T')[0];
